  const poolTemplate = createWinningDigitPool(winningRaw);
  const pool =
    poolTemplate != null ? new Map(poolTemplate) : null;

  return (
    <span
      className={cn(
        "inline-flex items-center tabular-nums tracking-wide",
        className,
      )}
      translate="no"
    >
      {chars.map((ch, i) => {
